import React from 'react';
import { Link } from 'react-router-dom';
import { Menu, X } from 'lucide-react';

const Navbar = () => {
  const [isMenuOpen, setIsMenuOpen] = React.useState(false);

  const toggleMenu = () => {
    setIsMenuOpen(!isMenuOpen);
  };

  return (
    <nav className="bg-gradient-to-b from-black to-gray-900 text-white py-6 shadow-soft-double border-b border-gray-800 font-inter">
      <div className="container mx-auto px-6 flex justify-between items-center">
        <div className="flex items-center">
          <span className="text-3xl font-bold text-indigo-400">Luxuria</span>
          <span className="ml-4 text-xl text-gray-300 opacity-80">| Elevate your stay</span>
        </div>

        <div className="hidden md:flex space-x-8">
          <Link to="/" className="hover:text-indigo-400 transition-colors duration-300">Home</Link>
          <Link to="/rooms" className="hover:text-indigo-400 transition-colors duration-300">Rooms</Link>
          <Link to="/services" className="hover:text-indigo-400 transition-colors duration-300">Services</Link>
          <Link to="/gallery" className="hover:text-indigo-400 transition-colors duration-300">Gallery</Link>
          <Link to="/contact" className="hover:text-indigo-400 transition-colors duration-300">Contact</Link>
        </div>

        <div className="md:hidden">
          <button onClick={toggleMenu} className="focus:outline-none">
            {isMenuOpen ? (
              <X className="h-8 w-8 text-indigo-400" />
            ) : (
              <Menu className="h-8 w-8 text-indigo-400" />
            )}
          </button>
        </div>
      </div>

      {isMenuOpen && (
        <div className="md:hidden bg-gray-800 bg-opacity-90 py-4 px-6 rounded-xl shadow-lg mt-4 border border-gray-700">
          <div className="flex flex-col space-y-4">
            <Link to="/" className="block py-2 px-4 rounded-md hover:bg-indigo-600 hover:text-white transition-colors duration-300">Home</Link>
            <Link to="/rooms" className="block py-2 px-4 rounded-md hover:bg-indigo-600 hover:text-white transition-colors duration-300">Rooms</Link>
            <Link to="/services" className="block py-2 px-4 rounded-md hover:bg-indigo-600 hover:text-white transition-colors duration-300">Services</Link>
            <Link to="/gallery" className="block py-2 px-4 rounded-md hover:bg-indigo-600 hover:text-white transition-colors duration-300">Gallery</Link>
            <Link to="/contact" className="block py-2 px-4 rounded-md hover:bg-indigo-600 hover:text-white transition-colors duration-300">Contact</Link>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

